#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <dirent.h>
#include <time.h>
#include <errno.h>

#define MAX_PATH 4096
#define MAX_LINE 1024
#define MAX_COMMIT 64
#define MAX_BLOB 64

static char repo_dir[MAX_PATH];
static char index_file[MAX_PATH];
static char refs_dir[MAX_PATH];
static char head_file[MAX_PATH];

void fatal(const char *msg) {
    perror(msg);
    exit(1);
}

void ensure_minigit() {
    if (access(".minigit", F_OK)) {
        fprintf(stderr, "minigt: not a minigit repository\n");
        exit(1);
    }
}

void init_paths() {
    snprintf(repo_dir, sizeof(repo_dir), ".minigit");
    snprintf(index_file, sizeof(index_file), ".minigit/index");
    snprintf(refs_dir, sizeof(refs_dir), ".minigit/refs");
    snprintf(head_file, sizeof(head_file), ".minigit/HEAD");
}

void cmd_init() {
    if (!access(".minigit", F_OK)) {
        fprintf(stderr, "minigit: repository already exists\n");
        exit(1);
    }
    mkdir(".minigit", 0755);
    mkdir(".minigit/objects", 0755);
    mkdir(".minigit/refs", 0755);
    FILE *f = fopen(".minigit/HEAD", "w");
    if (!f) fatal("fopen HEAD");
    fprintf(f, "ref: refs/heads/master\n");
    fclose(f);
}

char *sha(const char *path) {
    static char hash[MAX_LINE];
    snprintf(hash, sizeof(hash), "%lu", (unsigned long)time(NULL));
    return hash;
}

void cmd_add(const char *path) {
    ensure_minigit();
    char line[MAX_LINE];
    FILE *idx = fopen(index_file, "a+");
    if (!idx) fatal("fopen index");
    int found = 0;
    while (fgets(line, sizeof(line), idx)) {
        char *sp = strchr(line, ' ');
        if (sp && strncmp(line, path, sp - line) == 0) found = 1;
    }
    if (!found) fprintf(idx, "%s %s\n", path, sha(path));
    fclose(idx);
}

void cmd_commit(const char *msg) {
    ensure_minigit();
    char commit_path[MAX_PATH];
    snprintf(commit_path, sizeof(commit_path), ".minigit/objects/%s", sha(msg));
    FILE *f = fopen(commit_path, "w");
    if (!f) fatal("fopen commit");
    fprintf(f, "%s\n", msg);
    fclose(f);
    FILE *idx = fopen(index_file, "r");
    if (!idx) fatal("fopen index");
    char line[MAX_LINE];
    while (fgets(line, sizeof(line), idx)) {
        char *sp = strchr(line, ' ');
        if (sp) *sp = 0;
        fprintf(f, "%s\n", line);
    }
    fclose(idx);
    FILE *head = fopen(head_file, "r");
    if (!head) fatal("fopen HEAD");
    char ref[MAX_LINE];
    fgets(ref, sizeof(ref), head);
    fclose(head);
    char *ref_path = strchr(ref, ' ') ? ref + 5 : ref;
    ref_path[strcspn(ref_path, "\n")] = 0;
    char full_ref[MAX_PATH];
    snprintf(full_ref, sizeof(full_ref), ".minigit/%s", ref_path);
    FILE *ref_f = fopen(full_ref, "w");
    if (!ref_f) fatal("fopen ref");
    fprintf(ref_f, "%s\n", sha(msg));
    fclose(ref_f);
}

void cmd_log() {
    ensure_minigit();
    char ref[MAX_LINE];
    FILE *head = fopen(head_file, "r");
    if (!head) fatal("fopen HEAD");
    fgets(ref, sizeof(ref), head);
    fclose(head);
    char *ref_path = strchr(ref, ' ') ? ref + 5 : ref;
    ref_path[strcspn(ref_path, "\n")] = 0;
    char full_ref[MAX_PATH];
    snprintf(full_ref, sizeof(full_ref), ".minigit/%s", ref_path);
    FILE *f = fopen(full_ref, "r");
    if (!f) fatal("fopen ref");
    char commit[MAX_LINE];
    while (fgets(commit, sizeof(commit), f)) {
        commit[strcspn(commit, "\n")] = 0;
        char commit_path[MAX_PATH];
        snprintf(commit_path, sizeof(commit_path), ".minigit/objects/%s", commit);
        FILE *cf = fopen(commit_path, "r");
        if (!cf) fatal("fopen commit obj");
        char msg[MAX_LINE];
        fgets(msg, sizeof(msg), cf);
        msg[strcspn(msg, "\n")] = 0;
        printf("%s %s\n", commit, msg);
        fclose(cf);
    }
    fclose(f);
}

void cmd_checkout(const char *branch) {
    ensure_minigit();
    char ref_path[MAX_PATH];
    snprintf(ref_path, sizeof(ref_path), ".minigit/refs/heads/%s", branch);
    if (access(ref_path, F_OK)) {
        FILE *f = fopen(ref_path, "w");
        if (!f) fatal("fopen new branch");
        fclose(f);
    }
    FILE *head = fopen(head_file, "w");
    if (!head) fatal("fopen HEAD");
    fprintf(head, "ref: refs/heads/%s\n", branch);
    fclose(head);
}

void cmd_reset(const char *commit) {
    ensure_minigit();
    char head_ref[MAX_LINE];
    FILE *head = fopen(head_file, "r");
    if (!head) fatal("fopen HEAD");
    fgets(head_ref, sizeof(head_ref), head);
    fclose(head);
    char *ref_path = strchr(head_ref, ' ') ? head_ref + 5 : head_ref;
    ref_path[strcspn(ref_path, "\n")] = 0;
    char full_ref[MAX_PATH];
    snprintf(full_ref, sizeof(full_ref), ".minigit/%s", ref_path);
    FILE *ref = fopen(full_ref, "w");
    if (!ref) fatal("fopen ref");
    fprintf(ref, "%s\n", commit);
    fclose(ref);
}

int main(int argc, char **argv) {
    init_paths();
    if (argc < 2) {
        fprintf(stderr, "usage: minigit <command> [<args>]\n");
        return 1;
    }
    if (strcmp(argv[1], "init") == 0) {
        cmd_init();
    } else if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) fatal("usage: minigit add <file>");
        cmd_add(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 3) fatal("usage: minigit commit <message>");
        cmd_commit(argv[2]);
    } else if (strcmp(argv[1], "log") == 0) {
        cmd_log();
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) fatal("usage: minigit checkout <branch>");
        cmd_checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) fatal("usage: minigit reset <commit>");
        cmd_reset(argv[2]);
    } else {
        fprintf(stderr, "minigit: unknown command %s\n", argv[1]);
        return 1;
    }
    return 0;
}
